BEGIN;
DO $$
DECLARE
  v_subject_id UUID;
  v_topic_id UUID;
  v_test_id BIGINT;
BEGIN
  SELECT id INTO v_subject_id FROM test_subjects WHERE name ILIKE '%cardio%' ORDER BY id LIMIT 1;
  IF v_subject_id IS NULL THEN
    INSERT INTO test_subjects (name, description) VALUES ('Cardiovascular System', 'Cardiovascular notes') RETURNING id INTO v_subject_id;
  END IF;
  SELECT id INTO v_topic_id FROM test_topics WHERE name = 'Pacemakers & ICDs' ORDER BY (SELECT COUNT(*) FROM test_questions q WHERE q.topic_id = test_topics.id) DESC, created_at ASC LIMIT 1;
  IF v_topic_id IS NULL THEN
    INSERT INTO test_topics (subject_id, name, description, status) VALUES (v_subject_id, 'Pacemakers & ICDs', 'Device indications, troubleshooting, and chest pain priorities', 'published') RETURNING id INTO v_topic_id;
  END IF;
  SELECT id INTO v_test_id FROM tests WHERE is_active = true ORDER BY id LIMIT 1;
  IF v_test_id IS NULL THEN
    INSERT INTO tests (test_name, system_category, description, is_active)
    VALUES ('Cardiovascular System - Pacemakers and ICDs (Generated)', 'Cardiovascular System', 'Auto-generated NCLEX question set', true)
    RETURNING id INTO v_test_id;
  END IF;
  DELETE FROM test_questions WHERE topic_id = v_topic_id AND category = 'Pacemakers and ICDs - NCLEX';
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Pacemaker definition in this cardiovascular device scenario?', 'Which finding most strongly supports Pacemaker definition in this cardiovascular device scenario?', '[{"id": "a", "text": "Pacemakers only deliver defibrillation shocks in this note."}, {"id": "b", "text": "A pacemaker is an implanted device that delivers electrical impulses to maintain adequate heart rate and contraction."}, {"id": "c", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "d", "text": "Pacemakers are used to raise blood volume directly in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because A pacemaker is an implanted device that delivers electrical impulses to maintain adequate heart rate and contraction. Assess rhythm response and perfusion after pacing initiation.', 'Pacemakers and ICDs - NCLEX', false, 1, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes data; which interpretation best matches Temporary vs permanent pacing?', 'The nurse analyzes data; which interpretation best matches Temporary vs permanent pacing?', '[{"id": "a", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "b", "text": "Match pacing type to acute versus chronic rhythm support needs."}, {"id": "c", "text": "Permanent pacemakers are external bedside-only in this note."}, {"id": "d", "text": "Temporary pacing is lifelong default therapy in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Temporary pacing uses external wires (e.g., acute bradycardia/post-MI), while permanent pacing is surgically implanted under skin. Match pacing type to acute versus chronic rhythm support needs.', 'Pacemakers and ICDs - NCLEX', false, 2, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Bradycardia indication?', 'Which clinical judgment is most accurate regarding Bradycardia indication?', '[{"id": "a", "text": "Asymptomatic tachycardia is primary pacing indication in this note."}, {"id": "b", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "c", "text": "Bradycardia is never paced in this note."}, {"id": "d", "text": "Pacemaker indication includes symptomatic bradycardia with heart rate below 60 bpm."}]'::jsonb, '["d"]'::jsonb, 'Correct because Pacemaker indication includes symptomatic bradycardia with heart rate below 60 bpm. Treat symptomatic low-rate states to prevent syncope and hypoperfusion.', 'Pacemakers and ICDs - NCLEX', false, 3, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Heart block indication?', 'In urgent prioritization, which conclusion aligns with Heart block indication?', '[{"id": "a", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "b", "text": "AV block is contraindication to pacing in this note."}, {"id": "c", "text": "High-grade AV block should trigger prompt pacing preparedness."}, {"id": "d", "text": "This presentation is more consistent with Failure to capture."}]'::jsonb, '["c"]'::jsonb, 'Correct because Pacemaker indications include second-degree type II and third-degree AV block. High-grade AV block should trigger prompt pacing preparedness.', 'Pacemakers and ICDs - NCLEX', false, 4, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Other pacing indications?', 'Which statement best reflects Other pacing indications?', '[{"id": "a", "text": "Other listed pacing indications include asystole with reversible cause, sick sinus syndrome, and post-cardiac surgery prophylaxis."}, {"id": "b", "text": "Only ventricular tachycardia is paced in this note."}, {"id": "c", "text": "Pacemaker use is excluded after cardiac surgery in this note."}, {"id": "d", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}]'::jsonb, '["a"]'::jsonb, 'Correct because Other listed pacing indications include asystole with reversible cause, sick sinus syndrome, and post-cardiac surgery prophylaxis. Recognize broader pacing use beyond simple bradycardia.', 'Pacemakers and ICDs - NCLEX', false, 5, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports ECG post-implant monitoring in this cardiovascular device scenario?', 'Which finding most strongly supports ECG post-implant monitoring in this cardiovascular device scenario?', '[{"id": "a", "text": "ECG is unnecessary after implant in this note."}, {"id": "b", "text": "Correlate spikes with electrical/mechanical outcomes continuously."}, {"id": "c", "text": "Spikes indicate malfunction by default in this note."}, {"id": "d", "text": "This presentation is more consistent with Electromagnetic precautions."}]'::jsonb, '["b"]'::jsonb, 'Correct because Nursing care includes ECG monitoring to verify pacing spikes and appropriate response. Correlate spikes with electrical/mechanical outcomes continuously.', 'Pacemakers and ICDs - NCLEX', false, 6, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes data; which interpretation best matches Pacing threshold?', 'The nurse analyzes data; which interpretation best matches Pacing threshold?', '[{"id": "a", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "b", "text": "Pacing threshold is the lowest current needed to pace the heart."}, {"id": "c", "text": "Threshold has no relation to pacing effectiveness in this note."}, {"id": "d", "text": "This presentation is more consistent with Patient ID and symptom reporting."}]'::jsonb, '["b"]'::jsonb, 'Correct because Pacing threshold is the lowest current needed to pace the heart. Optimize threshold to ensure reliable capture with minimal energy.', 'Pacemakers and ICDs - NCLEX', false, 7, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Failure to pace?', 'Which clinical judgment is most accurate regarding Failure to pace?', '[{"id": "a", "text": "Failure to pace is normal after implantation in this note."}, {"id": "b", "text": "Failure to pace shows spike with no QRS in this note."}, {"id": "c", "text": "Recognize no-spike failure quickly to prevent brady-asystolic events."}, {"id": "d", "text": "Magnetic field precautions are optional and have no device implications."}]'::jsonb, '["c"]'::jsonb, 'Correct because Failure to pace is identified by absence of pacing spike when one is expected. Recognize no-spike failure quickly to prevent brady-asystolic events.', 'Pacemakers and ICDs - NCLEX', false, 8, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Failure to capture?', 'In urgent prioritization, which conclusion aligns with Failure to capture?', '[{"id": "a", "text": "Spike followed by QRS always indicates failure in this note."}, {"id": "b", "text": "Failure to capture is pacing spike without resulting QRS complex."}, {"id": "c", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "d", "text": "This presentation is more consistent with If ICD fires."}]'::jsonb, '["b"]'::jsonb, 'Correct because Failure to capture is pacing spike without resulting QRS complex. Spike-no-QRS pattern requires urgent evaluation of lead/output issues.', 'Pacemakers and ICDs - NCLEX', false, 9, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Arm movement restriction?', 'Which statement best reflects Arm movement restriction?', '[{"id": "a", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "b", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "c", "text": "Protect lead position in early post-op period."}, {"id": "d", "text": "Aggressive overhead arm exercise is encouraged immediately in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because After implant, restrict affected arm movement for 24–48 hours to prevent lead displacement. Protect lead position in early post-op period.', 'Pacemakers and ICDs - NCLEX', false, 10, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Electromagnetic precautions in this cardiovascular device scenario?', 'Which finding most strongly supports Electromagnetic precautions in this cardiovascular device scenario?', '[{"id": "a", "text": "Patients should avoid strong electromagnetic fields (e.g., MRI, arc welding, certain equipment)."}, {"id": "b", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "c", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "d", "text": "This presentation is more consistent with ICD storm emergency."}]'::jsonb, '["a"]'::jsonb, 'Correct because Patients should avoid strong electromagnetic fields (e.g., MRI, arc welding, certain equipment). Prevent device interference through exposure counseling.', 'Pacemakers and ICDs - NCLEX', false, 11, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes data; which interpretation best matches Patient ID and symptom reporting?', 'The nurse analyzes data; which interpretation best matches Patient ID and symptom reporting?', '[{"id": "a", "text": "Hiccups are always benign in this context in this note."}, {"id": "b", "text": "Device identification is unnecessary in emergencies in this note."}, {"id": "c", "text": "This presentation is more consistent with Chest pain initial priorities."}, {"id": "d", "text": "Early symptom reporting can identify displacement or pacing failure."}]'::jsonb, '["d"]'::jsonb, 'Correct because Patients should carry pacemaker ID card and report hiccups, dizziness, or syncope. Early symptom reporting can identify displacement or pacing failure.', 'Pacemakers and ICDs - NCLEX', false, 12, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding ICD function?', 'Which clinical judgment is most accurate regarding ICD function?', '[{"id": "a", "text": "ICD continuously monitors rhythm and delivers shock for ventricular fibrillation or ventricular tachycardia."}, {"id": "b", "text": "ICD does not treat ventricular arrhythmias in this note."}, {"id": "c", "text": "This presentation is more consistent with Chest pain workflow continuation."}, {"id": "d", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}]'::jsonb, '["a"]'::jsonb, 'Correct because ICD continuously monitors rhythm and delivers shock for ventricular fibrillation or ventricular tachycardia. Use ICD in patients at risk for sudden cardiac death from lethal ventricular rhythms.', 'Pacemakers and ICDs - NCLEX', false, 13, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with If ICD fires?', 'In urgent prioritization, which conclusion aligns with If ICD fires?', '[{"id": "a", "text": "ICD firing never requires follow-up in this note."}, {"id": "b", "text": "Post-shock self-management reduces injury and ensures urgent follow-up."}, {"id": "c", "text": "Exercise immediately after shock is advised in this note."}, {"id": "d", "text": "This presentation is more consistent with Nitroglycerin safety."}]'::jsonb, '["b"]'::jsonb, 'Correct because If ICD fires, patient should lie down, note time, and notify provider if symptoms continue. Post-shock self-management reduces injury and ensures urgent follow-up.', 'Pacemakers and ICDs - NCLEX', false, 14, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Bystander sensation with ICD?', 'Which statement best reflects Bystander sensation with ICD?', '[{"id": "a", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "b", "text": "This presentation is more consistent with Positioning HF/SOB."}, {"id": "c", "text": "People touching the patient during ICD discharge may feel mild shock that is not dangerous."}, {"id": "d", "text": "No one near patient feels anything in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because People touching the patient during ICD discharge may feel mild shock that is not dangerous. Provide reassurance to family and staff to reduce panic during discharge events.', 'Pacemakers and ICDs - NCLEX', false, 15, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports ICD storm emergency in this cardiovascular device scenario?', 'Which finding most strongly supports ICD storm emergency in this cardiovascular device scenario?', '[{"id": "a", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "b", "text": "ICD storm is routine expected function in this note."}, {"id": "c", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "d", "text": "Escalate recurrent shocks urgently for rhythm stabilization."}]'::jsonb, '["d"]'::jsonb, 'Correct because Repeated ICD firing should be reported immediately as an emergency (ICD storm). Escalate recurrent shocks urgently for rhythm stabilization.', 'Pacemakers and ICDs - NCLEX', false, 16, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes data; which interpretation best matches Chest pain initial priorities?', 'The nurse analyzes data; which interpretation best matches Chest pain initial priorities?', '[{"id": "a", "text": "Chest pain protocol starts with ABC assessment, oxygen if saturation <90%, vitals, and 12-lead ECG within 10 minutes."}, {"id": "b", "text": "Medications are given before ABC assessment in this note."}, {"id": "c", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "d", "text": "Magnetic field precautions are optional and have no device implications."}]'::jsonb, '["a"]'::jsonb, 'Correct because Chest pain protocol starts with ABC assessment, oxygen if saturation <90%, vitals, and 12-lead ECG within 10 minutes. Rapid physiologic stabilization and STEMI detection are first-line priorities.', 'Pacemakers and ICDs - NCLEX', false, 17, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Chest pain workflow continuation?', 'Which clinical judgment is most accurate regarding Chest pain workflow continuation?', '[{"id": "a", "text": "No labs are needed for chest pain in this note."}, {"id": "b", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "c", "text": "Establish access and objective diagnostics while initiating evidence-based medication sequence."}, {"id": "d", "text": "Heparin is given before aspirin in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Protocol includes large-bore IV access, labs (troponin, CK-MB, BMP), and meds sequence: aspirin, nitroglycerin, morphine if needed, then heparin. Establish access and objective diagnostics while initiating evidence-based medication sequence.', 'Pacemakers and ICDs - NCLEX', false, 18, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Nitroglycerin safety?', 'In urgent prioritization, which conclusion aligns with Nitroglycerin safety?', '[{"id": "a", "text": "Check blood pressure before nitroglycerin; avoid nitroglycerin if systolic BP <90 or recent sildenafil use within 24–48 hours."}, {"id": "b", "text": "Sildenafil timing has no relevance in this note."}, {"id": "c", "text": "NTG is safe regardless of BP in this note."}, {"id": "d", "text": "Magnetic field precautions are optional and have no device implications."}]'::jsonb, '["a"]'::jsonb, 'Correct because Check blood pressure before nitroglycerin; avoid nitroglycerin if systolic BP <90 or recent sildenafil use within 24–48 hours. Prevent severe hypotension from contraindicated nitrate administration.', 'Pacemakers and ICDs - NCLEX', false, 19, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Positioning HF/SOB?', 'Which statement best reflects Positioning HF/SOB?', '[{"id": "a", "text": "Use positioning to improve oxygenation while other therapies are prepared."}, {"id": "b", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "c", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "d", "text": "Flat Trendelenburg is best for HF/SOB in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because For heart failure/SOB, best position is HOB elevated 30–45° (Fowler) to reduce preload and ease breathing. Use positioning to improve oxygenation while other therapies are prepared.', 'Pacemakers and ICDs - NCLEX', false, 20, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Positioning hypotension/shock in this cardiovascular device scenario?', 'Which finding most strongly supports Positioning hypotension/shock in this cardiovascular device scenario?', '[{"id": "a", "text": "This presentation is more consistent with NCLEX perfusion tip."}, {"id": "b", "text": "Leg lowering improves hypotension in this note."}, {"id": "c", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "d", "text": "For hypotension/shock, position supine with legs elevated 15–30° to increase venous return."}]'::jsonb, '["d"]'::jsonb, 'Correct because For hypotension/shock, position supine with legs elevated 15–30° to increase venous return. Use immediate non-pharmacologic perfusion support while treating cause.', 'Pacemakers and ICDs - NCLEX', false, 21, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes data; which interpretation best matches Cardiogenic shock position caution?', 'The nurse analyzes data; which interpretation best matches Cardiogenic shock position caution?', '[{"id": "a", "text": "This presentation is more consistent with Pacemaker definition."}, {"id": "b", "text": "Balance BP support with cardiopulmonary tolerance in cardiogenic states."}, {"id": "c", "text": "Cardiogenic shock requires sitting upright always in this note."}, {"id": "d", "text": "Trendelenburg is first-line for cardiogenic shock in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because For cardiogenic shock, note recommends supine with caution and to avoid Trendelenburg. Balance BP support with cardiopulmonary tolerance in cardiogenic states.', 'Pacemakers and ICDs - NCLEX', false, 22, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Pericarditis and post-op positioning?', 'Which clinical judgment is most accurate regarding Pericarditis and post-op positioning?', '[{"id": "a", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "b", "text": "Pericarditis is best managed flat supine in this note."}, {"id": "c", "text": "Pericarditis position is sit up/lean forward; post-cardiac surgery preferred is semi-Fowler for comfort and lung expansion."}, {"id": "d", "text": "This presentation is more consistent with Temporary vs permanent pacing."}]'::jsonb, '["c"]'::jsonb, 'Correct because Pericarditis position is sit up/lean forward; post-cardiac surgery preferred is semi-Fowler for comfort and lung expansion. Condition-specific positioning can reduce pain and improve ventilation.', 'Pacemakers and ICDs - NCLEX', false, 23, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Lifestyle diet teaching?', 'In urgent prioritization, which conclusion aligns with Lifestyle diet teaching?', '[{"id": "a", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "b", "text": "This presentation is more consistent with Bradycardia indication."}, {"id": "c", "text": "Long-term dietary adherence reduces cardiovascular decompensation risk."}, {"id": "d", "text": "High-sodium canned foods are recommended in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Diet teaching includes sodium restriction <2 g/day, low saturated fat/cholesterol, high fiber/fruits/vegetables, and avoiding processed high-salt foods. Long-term dietary adherence reduces cardiovascular decompensation risk.', 'Pacemakers and ICDs - NCLEX', false, 24, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Lifestyle fluid/weight teaching?', 'Which statement best reflects Lifestyle fluid/weight teaching?', '[{"id": "a", "text": "Lifestyle instructions include no smoking, weight loss if BMI >25, fluid restriction 1.5–2 L/day in HF, and daily weight reporting if gain >2 lb."}, {"id": "b", "text": "Daily weight changes are irrelevant in this note."}, {"id": "c", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "d", "text": "This presentation is more consistent with Heart block indication."}]'::jsonb, '["a"]'::jsonb, 'Correct because Lifestyle instructions include no smoking, weight loss if BMI >25, fluid restriction 1.5–2 L/day in HF, and daily weight reporting if gain >2 lb. Self-monitoring and fluid control detect and prevent worsening heart failure.', 'Pacemakers and ICDs - NCLEX', false, 25, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports NCLEX perfusion tip in this cardiovascular device scenario?', 'Which finding most strongly supports NCLEX perfusion tip in this cardiovascular device scenario?', '[{"id": "a", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "b", "text": "Documentation precedes circulation in this note."}, {"id": "c", "text": "Stabilize airway-breathing-circulation before noncritical steps."}, {"id": "d", "text": "This presentation is more consistent with Other pacing indications."}]'::jsonb, '["c"]'::jsonb, 'Correct because NCLEX tip emphasizes avoiding Trendelenburg for hypotension and prioritizing oxygenation/circulation first. Stabilize airway-breathing-circulation before noncritical steps.', 'Pacemakers and ICDs - NCLEX', false, 26, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes data; which interpretation best matches Pacemaker definition?', 'The nurse analyzes data; which interpretation best matches Pacemaker definition?', '[{"id": "a", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "b", "text": "Pacemakers only deliver defibrillation shocks in this note."}, {"id": "c", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "d", "text": "A pacemaker is an implanted device that delivers electrical impulses to maintain adequate heart rate and contraction."}]'::jsonb, '["d"]'::jsonb, 'Correct because A pacemaker is an implanted device that delivers electrical impulses to maintain adequate heart rate and contraction. Assess rhythm response and perfusion after pacing initiation.', 'Pacemakers and ICDs - NCLEX', false, 27, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Temporary vs permanent pacing?', 'Which clinical judgment is most accurate regarding Temporary vs permanent pacing?', '[{"id": "a", "text": "Permanent pacemakers are external bedside-only in this note."}, {"id": "b", "text": "Temporary pacing is lifelong default therapy in this note."}, {"id": "c", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "d", "text": "Match pacing type to acute versus chronic rhythm support needs."}]'::jsonb, '["d"]'::jsonb, 'Correct because Temporary pacing uses external wires (e.g., acute bradycardia/post-MI), while permanent pacing is surgically implanted under skin. Match pacing type to acute versus chronic rhythm support needs.', 'Pacemakers and ICDs - NCLEX', false, 28, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Bradycardia indication?', 'In urgent prioritization, which conclusion aligns with Bradycardia indication?', '[{"id": "a", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "b", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "c", "text": "Pacemaker indication includes symptomatic bradycardia with heart rate below 60 bpm."}, {"id": "d", "text": "Bradycardia is never paced in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Pacemaker indication includes symptomatic bradycardia with heart rate below 60 bpm. Treat symptomatic low-rate states to prevent syncope and hypoperfusion.', 'Pacemakers and ICDs - NCLEX', false, 29, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Heart block indication?', 'Which statement best reflects Heart block indication?', '[{"id": "a", "text": "This presentation is more consistent with Failure to capture."}, {"id": "b", "text": "AV block is contraindication to pacing in this note."}, {"id": "c", "text": "High-grade AV block should trigger prompt pacing preparedness."}, {"id": "d", "text": "Magnetic field precautions are optional and have no device implications."}]'::jsonb, '["c"]'::jsonb, 'Correct because Pacemaker indications include second-degree type II and third-degree AV block. High-grade AV block should trigger prompt pacing preparedness.', 'Pacemakers and ICDs - NCLEX', false, 30, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Other pacing indications in this cardiovascular device scenario?', 'Which finding most strongly supports Other pacing indications in this cardiovascular device scenario?', '[{"id": "a", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "b", "text": "Other listed pacing indications include asystole with reversible cause, sick sinus syndrome, and post-cardiac surgery prophylaxis."}, {"id": "c", "text": "Pacemaker use is excluded after cardiac surgery in this note."}, {"id": "d", "text": "This presentation is more consistent with Arm movement restriction."}]'::jsonb, '["b"]'::jsonb, 'Correct because Other listed pacing indications include asystole with reversible cause, sick sinus syndrome, and post-cardiac surgery prophylaxis. Recognize broader pacing use beyond simple bradycardia.', 'Pacemakers and ICDs - NCLEX', false, 31, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes data; which interpretation best matches ECG post-implant monitoring?', 'The nurse analyzes data; which interpretation best matches ECG post-implant monitoring?', '[{"id": "a", "text": "This presentation is more consistent with Electromagnetic precautions."}, {"id": "b", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "c", "text": "Correlate spikes with electrical/mechanical outcomes continuously."}, {"id": "d", "text": "Spikes indicate malfunction by default in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Nursing care includes ECG monitoring to verify pacing spikes and appropriate response. Correlate spikes with electrical/mechanical outcomes continuously.', 'Pacemakers and ICDs - NCLEX', false, 32, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Pacing threshold?', 'Which clinical judgment is most accurate regarding Pacing threshold?', '[{"id": "a", "text": "This presentation is more consistent with Patient ID and symptom reporting."}, {"id": "b", "text": "Threshold is the maximum tolerated blood pressure in this note."}, {"id": "c", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "d", "text": "Pacing threshold is the lowest current needed to pace the heart."}]'::jsonb, '["d"]'::jsonb, 'Correct because Pacing threshold is the lowest current needed to pace the heart. Optimize threshold to ensure reliable capture with minimal energy.', 'Pacemakers and ICDs - NCLEX', false, 33, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Failure to pace?', 'In urgent prioritization, which conclusion aligns with Failure to pace?', '[{"id": "a", "text": "Recognize no-spike failure quickly to prevent brady-asystolic events."}, {"id": "b", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "c", "text": "Failure to pace is normal after implantation in this note."}, {"id": "d", "text": "This presentation is more consistent with ICD function."}]'::jsonb, '["a"]'::jsonb, 'Correct because Failure to pace is identified by absence of pacing spike when one is expected. Recognize no-spike failure quickly to prevent brady-asystolic events.', 'Pacemakers and ICDs - NCLEX', false, 34, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Failure to capture?', 'Which statement best reflects Failure to capture?', '[{"id": "a", "text": "This presentation is more consistent with If ICD fires."}, {"id": "b", "text": "Failure to capture means no spike present in this note."}, {"id": "c", "text": "Failure to capture is pacing spike without resulting QRS complex."}, {"id": "d", "text": "Spike followed by QRS always indicates failure in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Failure to capture is pacing spike without resulting QRS complex. Spike-no-QRS pattern requires urgent evaluation of lead/output issues.', 'Pacemakers and ICDs - NCLEX', false, 35, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Arm movement restriction in this cardiovascular device scenario?', 'Which finding most strongly supports Arm movement restriction in this cardiovascular device scenario?', '[{"id": "a", "text": "Protect lead position in early post-op period."}, {"id": "b", "text": "Arm restriction is unnecessary after implant in this note."}, {"id": "c", "text": "Aggressive overhead arm exercise is encouraged immediately in this note."}, {"id": "d", "text": "This presentation is more consistent with Bystander sensation with ICD."}]'::jsonb, '["a"]'::jsonb, 'Correct because After implant, restrict affected arm movement for 24–48 hours to prevent lead displacement. Protect lead position in early post-op period.', 'Pacemakers and ICDs - NCLEX', false, 36, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes data; which interpretation best matches Electromagnetic precautions?', 'The nurse analyzes data; which interpretation best matches Electromagnetic precautions?', '[{"id": "a", "text": "All magnetic exposures are harmless in this note."}, {"id": "b", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "c", "text": "Arc welding is recommended with pacemakers in this note."}, {"id": "d", "text": "Patients should avoid strong electromagnetic fields (e.g., MRI, arc welding, certain equipment)."}]'::jsonb, '["d"]'::jsonb, 'Correct because Patients should avoid strong electromagnetic fields (e.g., MRI, arc welding, certain equipment). Prevent device interference through exposure counseling.', 'Pacemakers and ICDs - NCLEX', false, 37, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Patient ID and symptom reporting?', 'Which clinical judgment is most accurate regarding Patient ID and symptom reporting?', '[{"id": "a", "text": "This presentation is more consistent with Chest pain initial priorities."}, {"id": "b", "text": "Hiccups are always benign in this context in this note."}, {"id": "c", "text": "Device identification is unnecessary in emergencies in this note."}, {"id": "d", "text": "Early symptom reporting can identify displacement or pacing failure."}]'::jsonb, '["d"]'::jsonb, 'Correct because Patients should carry pacemaker ID card and report hiccups, dizziness, or syncope. Early symptom reporting can identify displacement or pacing failure.', 'Pacemakers and ICDs - NCLEX', false, 38, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with ICD function?', 'In urgent prioritization, which conclusion aligns with ICD function?', '[{"id": "a", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "b", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "c", "text": "ICD is for sinus bradycardia only in this note."}, {"id": "d", "text": "ICD continuously monitors rhythm and delivers shock for ventricular fibrillation or ventricular tachycardia."}]'::jsonb, '["d"]'::jsonb, 'Correct because ICD continuously monitors rhythm and delivers shock for ventricular fibrillation or ventricular tachycardia. Use ICD in patients at risk for sudden cardiac death from lethal ventricular rhythms.', 'Pacemakers and ICDs - NCLEX', false, 39, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects If ICD fires?', 'Which statement best reflects If ICD fires?', '[{"id": "a", "text": "This presentation is more consistent with Nitroglycerin safety."}, {"id": "b", "text": "Exercise immediately after shock is advised in this note."}, {"id": "c", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "d", "text": "Post-shock self-management reduces injury and ensures urgent follow-up."}]'::jsonb, '["d"]'::jsonb, 'Correct because If ICD fires, patient should lie down, note time, and notify provider if symptoms continue. Post-shock self-management reduces injury and ensures urgent follow-up.', 'Pacemakers and ICDs - NCLEX', false, 40, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Bystander sensation with ICD in this cardiovascular device scenario?', 'Which finding most strongly supports Bystander sensation with ICD in this cardiovascular device scenario?', '[{"id": "a", "text": "People touching the patient during ICD discharge may feel mild shock that is not dangerous."}, {"id": "b", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "c", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "d", "text": "This presentation is more consistent with Positioning HF/SOB."}]'::jsonb, '["a"]'::jsonb, 'Correct because People touching the patient during ICD discharge may feel mild shock that is not dangerous. Provide reassurance to family and staff to reduce panic during discharge events.', 'Pacemakers and ICDs - NCLEX', false, 41, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes data; which interpretation best matches ICD storm emergency?', 'The nurse analyzes data; which interpretation best matches ICD storm emergency?', '[{"id": "a", "text": "Escalate recurrent shocks urgently for rhythm stabilization."}, {"id": "b", "text": "ICD storm is routine expected function in this note."}, {"id": "c", "text": "Repeated shocks can be ignored if conscious in this note."}, {"id": "d", "text": "Magnetic field precautions are optional and have no device implications."}]'::jsonb, '["a"]'::jsonb, 'Correct because Repeated ICD firing should be reported immediately as an emergency (ICD storm). Escalate recurrent shocks urgently for rhythm stabilization.', 'Pacemakers and ICDs - NCLEX', false, 42, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Chest pain initial priorities?', 'Which clinical judgment is most accurate regarding Chest pain initial priorities?', '[{"id": "a", "text": "Chest pain protocol starts with ABC assessment, oxygen if saturation <90%, vitals, and 12-lead ECG within 10 minutes."}, {"id": "b", "text": "This presentation is more consistent with Cardiogenic shock position caution."}, {"id": "c", "text": "Medications are given before ABC assessment in this note."}, {"id": "d", "text": "12-lead ECG can be delayed several hours in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Chest pain protocol starts with ABC assessment, oxygen if saturation <90%, vitals, and 12-lead ECG within 10 minutes. Rapid physiologic stabilization and STEMI detection are first-line priorities.', 'Pacemakers and ICDs - NCLEX', false, 43, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Chest pain workflow continuation?', 'In urgent prioritization, which conclusion aligns with Chest pain workflow continuation?', '[{"id": "a", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "b", "text": "This presentation is more consistent with Pericarditis and post-op positioning."}, {"id": "c", "text": "Heparin is given before aspirin in this note."}, {"id": "d", "text": "Establish access and objective diagnostics while initiating evidence-based medication sequence."}]'::jsonb, '["d"]'::jsonb, 'Correct because Protocol includes large-bore IV access, labs (troponin, CK-MB, BMP), and meds sequence: aspirin, nitroglycerin, morphine if needed, then heparin. Establish access and objective diagnostics while initiating evidence-based medication sequence.', 'Pacemakers and ICDs - NCLEX', false, 44, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Nitroglycerin safety?', 'Which statement best reflects Nitroglycerin safety?', '[{"id": "a", "text": "Sildenafil timing has no relevance in this note."}, {"id": "b", "text": "This presentation is more consistent with Lifestyle diet teaching."}, {"id": "c", "text": "Check blood pressure before nitroglycerin; avoid nitroglycerin if systolic BP <90 or recent sildenafil use within 24–48 hours."}, {"id": "d", "text": "NTG is safe regardless of BP in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Check blood pressure before nitroglycerin; avoid nitroglycerin if systolic BP <90 or recent sildenafil use within 24–48 hours. Prevent severe hypotension from contraindicated nitrate administration.', 'Pacemakers and ICDs - NCLEX', false, 45, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Positioning HF/SOB in this cardiovascular device scenario?', 'Which finding most strongly supports Positioning HF/SOB in this cardiovascular device scenario?', '[{"id": "a", "text": "Flat Trendelenburg is best for HF/SOB in this note."}, {"id": "b", "text": "Position has no respiratory impact in this note."}, {"id": "c", "text": "This presentation is more consistent with Lifestyle fluid/weight teaching."}, {"id": "d", "text": "Use positioning to improve oxygenation while other therapies are prepared."}]'::jsonb, '["d"]'::jsonb, 'Correct because For heart failure/SOB, best position is HOB elevated 30–45° (Fowler) to reduce preload and ease breathing. Use positioning to improve oxygenation while other therapies are prepared.', 'Pacemakers and ICDs - NCLEX', false, 46, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes data; which interpretation best matches Positioning hypotension/shock?', 'The nurse analyzes data; which interpretation best matches Positioning hypotension/shock?', '[{"id": "a", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "b", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}, {"id": "c", "text": "For hypotension/shock, position supine with legs elevated 15–30° to increase venous return."}, {"id": "d", "text": "Leg lowering improves hypotension in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because For hypotension/shock, position supine with legs elevated 15–30° to increase venous return. Use immediate non-pharmacologic perfusion support while treating cause.', 'Pacemakers and ICDs - NCLEX', false, 47, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Cardiogenic shock position caution?', 'Which clinical judgment is most accurate regarding Cardiogenic shock position caution?', '[{"id": "a", "text": "Cardiogenic shock requires sitting upright always in this note."}, {"id": "b", "text": "Balance BP support with cardiopulmonary tolerance in cardiogenic states."}, {"id": "c", "text": "This presentation is more consistent with Pacemaker definition."}, {"id": "d", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}]'::jsonb, '["b"]'::jsonb, 'Correct because For cardiogenic shock, note recommends supine with caution and to avoid Trendelenburg. Balance BP support with cardiopulmonary tolerance in cardiogenic states.', 'Pacemakers and ICDs - NCLEX', false, 48, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which conclusion aligns with Pericarditis and post-op positioning?', 'In urgent prioritization, which conclusion aligns with Pericarditis and post-op positioning?', '[{"id": "a", "text": "This presentation is more consistent with Temporary vs permanent pacing."}, {"id": "b", "text": "Pericarditis position is sit up/lean forward; post-cardiac surgery preferred is semi-Fowler for comfort and lung expansion."}, {"id": "c", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "d", "text": "Pericarditis is best managed flat supine in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Pericarditis position is sit up/lean forward; post-cardiac surgery preferred is semi-Fowler for comfort and lung expansion. Condition-specific positioning can reduce pain and improve ventilation.', 'Pacemakers and ICDs - NCLEX', false, 49, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Lifestyle diet teaching?', 'Which statement best reflects Lifestyle diet teaching?', '[{"id": "a", "text": "Long-term dietary adherence reduces cardiovascular decompensation risk."}, {"id": "b", "text": "High-sodium canned foods are recommended in this note."}, {"id": "c", "text": "Magnetic field precautions are optional and have no device implications."}, {"id": "d", "text": "Immediate reassessment is unnecessary when symptoms fluctuate briefly."}]'::jsonb, '["a"]'::jsonb, 'Correct because Diet teaching includes sodium restriction <2 g/day, low saturated fat/cholesterol, high fiber/fruits/vegetables, and avoiding processed high-salt foods. Long-term dietary adherence reduces cardiovascular decompensation risk.', 'Pacemakers and ICDs - NCLEX', false, 50, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Pacemaker definition. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Pacemaker definition. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Pacemakers are used to raise blood volume directly in this note."}, {"id": "b", "text": "Pacemakers only deliver defibrillation shocks in this note."}, {"id": "c", "text": "Device supports contraction when intrinsic rate is insufficient."}, {"id": "d", "text": "Goal is adequate heart rate/perfusion."}, {"id": "e", "text": "Pacemakers deliver electrical impulses."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: A pacemaker is an implanted device that delivers electrical impulses to maintain adequate heart rate and contraction.', 'Pacemakers and ICDs - NCLEX', true, 51, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Temporary vs permanent pacing, which statements are correct? (Select all that apply)', 'For management involving Temporary vs permanent pacing, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Temporary pacing can be used post-MI in this note."}, {"id": "b", "text": "Permanent pacemakers are external bedside-only in this note."}, {"id": "c", "text": "Temporary pacing is lifelong default therapy in this note."}, {"id": "d", "text": "Temporary and permanent pacing have different use contexts."}, {"id": "e", "text": "Permanent systems are implanted under skin."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Temporary pacing uses external wires (e.g., acute bradycardia/post-MI), while permanent pacing is surgically implanted under skin.', 'Pacemakers and ICDs - NCLEX', true, 52, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Bradycardia indication. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Bradycardia indication. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Symptomatic bradycardia is listed indication."}, {"id": "b", "text": "Bradycardia is never paced in this note."}, {"id": "c", "text": "Symptoms drive urgency for intervention."}, {"id": "d", "text": "Asymptomatic tachycardia is primary pacing indication in this note."}, {"id": "e", "text": "<60 bpm threshold appears in note context."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Pacemaker indication includes symptomatic bradycardia with heart rate below 60 bpm.', 'Pacemakers and ICDs - NCLEX', true, 53, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Heart block indication? (Select all that apply)', 'During reassessment, which observations support Heart block indication? (Select all that apply)', '[{"id": "a", "text": "Second-degree type II block is listed indication."}, {"id": "b", "text": "First-degree block is the only mandatory pacing indication in this note."}, {"id": "c", "text": "Third-degree block is listed indication."}, {"id": "d", "text": "AV block is contraindication to pacing in this note."}, {"id": "e", "text": "Electrical signal interruption between atria and ventricles is emphasized."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Pacemaker indications include second-degree type II and third-degree AV block.', 'Pacemakers and ICDs - NCLEX', true, 54, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Other pacing indications in this note? (Select all that apply)', 'Which clues are consistent with Other pacing indications in this note? (Select all that apply)', '[{"id": "a", "text": "Only ventricular tachycardia is paced in this note."}, {"id": "b", "text": "Asystole with reversible cause is listed indication."}, {"id": "c", "text": "Pacemaker use is excluded after cardiac surgery in this note."}, {"id": "d", "text": "Post-cardiac surgery prophylaxis is listed use."}, {"id": "e", "text": "Sick sinus syndrome is listed indication."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Other listed pacing indications include asystole with reversible cause, sick sinus syndrome, and post-cardiac surgery prophylaxis.', 'Pacemakers and ICDs - NCLEX', true, 55, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for ECG post-implant monitoring. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for ECG post-implant monitoring. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Pacing spikes should be visible/appropriate."}, {"id": "b", "text": "ECG monitoring is immediate post-implant priority."}, {"id": "c", "text": "Rhythm verification is central to pacemaker safety."}, {"id": "d", "text": "ECG is unnecessary after implant in this note."}, {"id": "e", "text": "Spikes indicate malfunction by default in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Nursing care includes ECG monitoring to verify pacing spikes and appropriate response.', 'Pacemakers and ICDs - NCLEX', true, 56, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Pacing threshold, which statements are correct? (Select all that apply)', 'For management involving Pacing threshold, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Threshold assessment is listed nursing priority."}, {"id": "b", "text": "Threshold is the maximum tolerated blood pressure in this note."}, {"id": "c", "text": "Capture reliability depends on adequate output above threshold."}, {"id": "d", "text": "Threshold has no relation to pacing effectiveness in this note."}, {"id": "e", "text": "Threshold refers to minimum effective current."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Pacing threshold is the lowest current needed to pace the heart.', 'Pacemakers and ICDs - NCLEX', true, 57, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Failure to pace. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Failure to pace. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Failure to pace is normal after implantation in this note."}, {"id": "b", "text": "Immediate troubleshooting is required when no spike appears."}, {"id": "c", "text": "No pacing spike can indicate failure to pace."}, {"id": "d", "text": "Failure to pace shows spike with no QRS in this note."}, {"id": "e", "text": "Expected pacing without spike is abnormal."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Failure to pace is identified by absence of pacing spike when one is expected.', 'Pacemakers and ICDs - NCLEX', true, 58, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Failure to capture? (Select all that apply)', 'During reassessment, which observations support Failure to capture? (Select all that apply)', '[{"id": "a", "text": "Failure to capture means no spike present in this note."}, {"id": "b", "text": "Capture failure threatens perfusion."}, {"id": "c", "text": "Spike followed by QRS always indicates failure in this note."}, {"id": "d", "text": "Electrical output without depolarization is abnormal."}, {"id": "e", "text": "Spike without QRS defines failure to capture."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Failure to capture is pacing spike without resulting QRS complex.', 'Pacemakers and ICDs - NCLEX', true, 59, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Arm movement restriction in this note? (Select all that apply)', 'Which clues are consistent with Arm movement restriction in this note? (Select all that apply)', '[{"id": "a", "text": "Arm restriction duration is 24–48 hours."}, {"id": "b", "text": "Arm restriction is unnecessary after implant in this note."}, {"id": "c", "text": "Post-op mobility guidance is part of nursing care."}, {"id": "d", "text": "Reason is prevention of lead displacement."}, {"id": "e", "text": "Aggressive overhead arm exercise is encouraged immediately in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: After implant, restrict affected arm movement for 24–48 hours to prevent lead displacement.', 'Pacemakers and ICDs - NCLEX', true, 60, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Electromagnetic precautions. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Electromagnetic precautions. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "MRI is listed as concern in note context."}, {"id": "b", "text": "Strong electromagnetic fields should be avoided."}, {"id": "c", "text": "Arc welding is recommended with pacemakers in this note."}, {"id": "d", "text": "Device safety teaching includes environmental risks."}, {"id": "e", "text": "All magnetic exposures are harmless in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Patients should avoid strong electromagnetic fields (e.g., MRI, arc welding, certain equipment).', 'Pacemakers and ICDs - NCLEX', true, 61, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Patient ID and symptom reporting, which statements are correct? (Select all that apply)', 'For management involving Patient ID and symptom reporting, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Device identification is unnecessary in emergencies in this note."}, {"id": "b", "text": "Pacemaker ID card is recommended."}, {"id": "c", "text": "Dizziness/syncope should be reported."}, {"id": "d", "text": "Hiccups are always benign in this context in this note."}, {"id": "e", "text": "Hiccups can signal diaphragm stimulation/lead displacement."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Patients should carry pacemaker ID card and report hiccups, dizziness, or syncope.', 'Pacemakers and ICDs - NCLEX', true, 62, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around ICD function. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around ICD function. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "ICD shocks V-fib/V-tach per note."}, {"id": "b", "text": "ICD is for sinus bradycardia only in this note."}, {"id": "c", "text": "ICD is indicated for sudden death risk patients."}, {"id": "d", "text": "ICD does not treat ventricular arrhythmias in this note."}, {"id": "e", "text": "ICD monitors rhythm continuously."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: ICD continuously monitors rhythm and delivers shock for ventricular fibrillation or ventricular tachycardia.', 'Pacemakers and ICDs - NCLEX', true, 63, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support If ICD fires? (Select all that apply)', 'During reassessment, which observations support If ICD fires? (Select all that apply)', '[{"id": "a", "text": "Lie down after ICD discharge is recommended."}, {"id": "b", "text": "ICD firing never requires follow-up in this note."}, {"id": "c", "text": "Persistent symptoms require provider notification."}, {"id": "d", "text": "Documenting shock time is recommended."}, {"id": "e", "text": "Exercise immediately after shock is advised in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: If ICD fires, patient should lie down, note time, and notify provider if symptoms continue.', 'Pacemakers and ICDs - NCLEX', true, 64, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Bystander sensation with ICD in this note? (Select all that apply)', 'Which clues are consistent with Bystander sensation with ICD in this note? (Select all that apply)', '[{"id": "a", "text": "Bystanders may feel mild shock."}, {"id": "b", "text": "Education reduces fear around ICD events."}, {"id": "c", "text": "Mild shock to bystander is noted as not dangerous."}, {"id": "d", "text": "No one near patient feels anything in this note."}, {"id": "e", "text": "ICD discharge is fatal to bystanders in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: People touching the patient during ICD discharge may feel mild shock that is not dangerous.', 'Pacemakers and ICDs - NCLEX', true, 65, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for ICD storm emergency. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for ICD storm emergency. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Immediate reporting is required."}, {"id": "b", "text": "Repeated firing is emergency in this note."}, {"id": "c", "text": "Repeated shocks can be ignored if conscious in this note."}, {"id": "d", "text": "Storm implies unstable arrhythmia burden."}, {"id": "e", "text": "ICD storm is routine expected function in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Repeated ICD firing should be reported immediately as an emergency (ICD storm).', 'Pacemakers and ICDs - NCLEX', true, 66, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Chest pain initial priorities, which statements are correct? (Select all that apply)', 'For management involving Chest pain initial priorities, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "12-lead ECG can be delayed several hours in this note."}, {"id": "b", "text": "ECG target is within 10 minutes."}, {"id": "c", "text": "Medications are given before ABC assessment in this note."}, {"id": "d", "text": "Oxygen threshold is O2 sat <90% in note."}, {"id": "e", "text": "ABCs come first in chest pain approach."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Chest pain protocol starts with ABC assessment, oxygen if saturation <90%, vitals, and 12-lead ECG within 10 minutes.', 'Pacemakers and ICDs - NCLEX', true, 67, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Chest pain workflow continuation. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Chest pain workflow continuation. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Aspirin then nitroglycerin then morphine/heparin sequence is listed."}, {"id": "b", "text": "No labs are needed for chest pain in this note."}, {"id": "c", "text": "Large-bore IV is listed."}, {"id": "d", "text": "Troponin/CK-MB/BMP are listed labs."}, {"id": "e", "text": "Heparin is given before aspirin in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Protocol includes large-bore IV access, labs (troponin, CK-MB, BMP), and meds sequence: aspirin, nitroglycerin, morphine if needed, then heparin.', 'Pacemakers and ICDs - NCLEX', true, 68, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Nitroglycerin safety? (Select all that apply)', 'During reassessment, which observations support Nitroglycerin safety? (Select all that apply)', '[{"id": "a", "text": "NTG is safe regardless of BP in this note."}, {"id": "b", "text": "Recent sildenafil is contraindication in this note."}, {"id": "c", "text": "BP check before NTG is emphasized."}, {"id": "d", "text": "SBP <90 is NTG hold criterion."}, {"id": "e", "text": "Sildenafil timing has no relevance in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Check blood pressure before nitroglycerin; avoid nitroglycerin if systolic BP <90 or recent sildenafil use within 24–48 hours.', 'Pacemakers and ICDs - NCLEX', true, 69, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Positioning HF/SOB in this note? (Select all that apply)', 'Which clues are consistent with Positioning HF/SOB in this note? (Select all that apply)', '[{"id": "a", "text": "Fowler position 30–45° is listed for HF/SOB."}, {"id": "b", "text": "Flat Trendelenburg is best for HF/SOB in this note."}, {"id": "c", "text": "Positioning reduces preload in this note."}, {"id": "d", "text": "Breathing relief is rationale for elevated HOB."}, {"id": "e", "text": "Position has no respiratory impact in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: For heart failure/SOB, best position is HOB elevated 30–45° (Fowler) to reduce preload and ease breathing.', 'Pacemakers and ICDs - NCLEX', true, 70, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Positioning hypotension/shock. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Positioning hypotension/shock. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Rationale is increased venous return."}, {"id": "b", "text": "Sit upright is best for hypotensive shock in this note."}, {"id": "c", "text": "Supine with legs elevated is listed for hypotension/shock."}, {"id": "d", "text": "Positioning is an early supportive intervention."}, {"id": "e", "text": "Leg lowering improves hypotension in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: For hypotension/shock, position supine with legs elevated 15–30° to increase venous return.', 'Pacemakers and ICDs - NCLEX', true, 71, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Cardiogenic shock position caution, which statements are correct? (Select all that apply)', 'For management involving Cardiogenic shock position caution, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Trendelenburg is avoided in cardiogenic shock."}, {"id": "b", "text": "Supine positioning is listed with caution."}, {"id": "c", "text": "Positioning differs from routine assumptions."}, {"id": "d", "text": "Cardiogenic shock requires sitting upright always in this note."}, {"id": "e", "text": "Trendelenburg is first-line for cardiogenic shock in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: For cardiogenic shock, note recommends supine with caution and to avoid Trendelenburg.', 'Pacemakers and ICDs - NCLEX', true, 72, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Pericarditis and post-op positioning. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Pericarditis and post-op positioning. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Post-cardiac surgery semi-Fowler is listed."}, {"id": "b", "text": "Post-op position should always be Trendelenburg in this note."}, {"id": "c", "text": "Lung expansion is rationale for semi-Fowler post-op."}, {"id": "d", "text": "Pericarditis is best managed flat supine in this note."}, {"id": "e", "text": "Pericarditis relieved by sit up and leaning forward."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis position is sit up/lean forward; post-cardiac surgery preferred is semi-Fowler for comfort and lung expansion.', 'Pacemakers and ICDs - NCLEX', true, 73, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Lifestyle diet teaching? (Select all that apply)', 'During reassessment, which observations support Lifestyle diet teaching? (Select all that apply)', '[{"id": "a", "text": "High-sodium canned foods are recommended in this note."}, {"id": "b", "text": "Fiber should be minimized in this note."}, {"id": "c", "text": "Sodium target <2 g/day is listed."}, {"id": "d", "text": "Processed foods/deli meats/canned soups are discouraged."}, {"id": "e", "text": "High-fiber fruits/vegetables are recommended."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Diet teaching includes sodium restriction <2 g/day, low saturated fat/cholesterol, high fiber/fruits/vegetables, and avoiding processed high-salt foods.', 'Pacemakers and ICDs - NCLEX', true, 74, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Lifestyle fluid/weight teaching in this note? (Select all that apply)', 'Which clues are consistent with Lifestyle fluid/weight teaching in this note? (Select all that apply)', '[{"id": "a", "text": "Fluid restriction 1.5–2 L/day is listed for HF."}, {"id": "b", "text": "Daily weight changes are irrelevant in this note."}, {"id": "c", "text": "Daily weight gain >2 lb should be reported."}, {"id": "d", "text": "Smoking cessation and weight-loss goals are included."}, {"id": "e", "text": "Unlimited fluids are advised for HF in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Lifestyle instructions include no smoking, weight loss if BMI >25, fluid restriction 1.5–2 L/day in HF, and daily weight reporting if gain >2 lb.', 'Pacemakers and ICDs - NCLEX', true, 75, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for NCLEX perfusion tip. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for NCLEX perfusion tip. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Oxygenation is prioritized first."}, {"id": "b", "text": "Avoid Trendelenburg in hypotension is explicit tip."}, {"id": "c", "text": "Circulation support is prioritized first."}, {"id": "d", "text": "Trendelenburg is preferred for all hypotension in this note."}, {"id": "e", "text": "Documentation precedes circulation in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: NCLEX tip emphasizes avoiding Trendelenburg for hypotension and prioritizing oxygenation/circulation first.', 'Pacemakers and ICDs - NCLEX', true, 76, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Pacemaker definition, which statements are correct? (Select all that apply)', 'For management involving Pacemaker definition, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Pacemakers deliver electrical impulses."}, {"id": "b", "text": "Device supports contraction when intrinsic rate is insufficient."}, {"id": "c", "text": "Pacemakers are used to raise blood volume directly in this note."}, {"id": "d", "text": "Goal is adequate heart rate/perfusion."}, {"id": "e", "text": "Pacemakers only deliver defibrillation shocks in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: A pacemaker is an implanted device that delivers electrical impulses to maintain adequate heart rate and contraction.', 'Pacemakers and ICDs - NCLEX', true, 77, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Temporary vs permanent pacing. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Temporary vs permanent pacing. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Temporary pacing is lifelong default therapy in this note."}, {"id": "b", "text": "Permanent pacemakers are external bedside-only in this note."}, {"id": "c", "text": "Temporary pacing can be used post-MI in this note."}, {"id": "d", "text": "Permanent systems are implanted under skin."}, {"id": "e", "text": "Temporary and permanent pacing have different use contexts."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Temporary pacing uses external wires (e.g., acute bradycardia/post-MI), while permanent pacing is surgically implanted under skin.', 'Pacemakers and ICDs - NCLEX', true, 78, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Bradycardia indication? (Select all that apply)', 'During reassessment, which observations support Bradycardia indication? (Select all that apply)', '[{"id": "a", "text": "<60 bpm threshold appears in note context."}, {"id": "b", "text": "Asymptomatic tachycardia is primary pacing indication in this note."}, {"id": "c", "text": "Bradycardia is never paced in this note."}, {"id": "d", "text": "Symptoms drive urgency for intervention."}, {"id": "e", "text": "Symptomatic bradycardia is listed indication."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Pacemaker indication includes symptomatic bradycardia with heart rate below 60 bpm.', 'Pacemakers and ICDs - NCLEX', true, 79, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Heart block indication in this note? (Select all that apply)', 'Which clues are consistent with Heart block indication in this note? (Select all that apply)', '[{"id": "a", "text": "Second-degree type II block is listed indication."}, {"id": "b", "text": "Electrical signal interruption between atria and ventricles is emphasized."}, {"id": "c", "text": "Third-degree block is listed indication."}, {"id": "d", "text": "AV block is contraindication to pacing in this note."}, {"id": "e", "text": "First-degree block is the only mandatory pacing indication in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Pacemaker indications include second-degree type II and third-degree AV block.', 'Pacemakers and ICDs - NCLEX', true, 80, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Other pacing indications. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Other pacing indications. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Only ventricular tachycardia is paced in this note."}, {"id": "b", "text": "Pacemaker use is excluded after cardiac surgery in this note."}, {"id": "c", "text": "Sick sinus syndrome is listed indication."}, {"id": "d", "text": "Post-cardiac surgery prophylaxis is listed use."}, {"id": "e", "text": "Asystole with reversible cause is listed indication."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Other listed pacing indications include asystole with reversible cause, sick sinus syndrome, and post-cardiac surgery prophylaxis.', 'Pacemakers and ICDs - NCLEX', true, 81, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving ECG post-implant monitoring, which statements are correct? (Select all that apply)', 'For management involving ECG post-implant monitoring, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Pacing spikes should be visible/appropriate."}, {"id": "b", "text": "ECG is unnecessary after implant in this note."}, {"id": "c", "text": "Rhythm verification is central to pacemaker safety."}, {"id": "d", "text": "ECG monitoring is immediate post-implant priority."}, {"id": "e", "text": "Spikes indicate malfunction by default in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Nursing care includes ECG monitoring to verify pacing spikes and appropriate response.', 'Pacemakers and ICDs - NCLEX', true, 82, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Pacing threshold. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Pacing threshold. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Capture reliability depends on adequate output above threshold."}, {"id": "b", "text": "Threshold has no relation to pacing effectiveness in this note."}, {"id": "c", "text": "Threshold assessment is listed nursing priority."}, {"id": "d", "text": "Threshold refers to minimum effective current."}, {"id": "e", "text": "Threshold is the maximum tolerated blood pressure in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Pacing threshold is the lowest current needed to pace the heart.', 'Pacemakers and ICDs - NCLEX', true, 83, 1, true);
