  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Failure to capture in this note? (Select all that apply)', 'Which clues are consistent with Failure to capture in this note? (Select all that apply)', '[{"id": "a", "text": "Capture failure threatens perfusion."}, {"id": "b", "text": "Failure to capture means no spike present in this note."}, {"id": "c", "text": "Spike followed by QRS always indicates failure in this note."}, {"id": "d", "text": "Electrical output without depolarization is abnormal."}, {"id": "e", "text": "Spike without QRS defines failure to capture."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Failure to capture is pacing spike without resulting QRS complex.', 'Pacemakers and ICDs - NCLEX', true, 85, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Arm movement restriction. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Arm movement restriction. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Arm restriction duration is 24–48 hours."}, {"id": "b", "text": "Aggressive overhead arm exercise is encouraged immediately in this note."}, {"id": "c", "text": "Reason is prevention of lead displacement."}, {"id": "d", "text": "Arm restriction is unnecessary after implant in this note."}, {"id": "e", "text": "Post-op mobility guidance is part of nursing care."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: After implant, restrict affected arm movement for 24–48 hours to prevent lead displacement.', 'Pacemakers and ICDs - NCLEX', true, 86, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Electromagnetic precautions, which statements are correct? (Select all that apply)', 'For management involving Electromagnetic precautions, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Device safety teaching includes environmental risks."}, {"id": "b", "text": "Arc welding is recommended with pacemakers in this note."}, {"id": "c", "text": "Strong electromagnetic fields should be avoided."}, {"id": "d", "text": "All magnetic exposures are harmless in this note."}, {"id": "e", "text": "MRI is listed as concern in note context."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Patients should avoid strong electromagnetic fields (e.g., MRI, arc welding, certain equipment).', 'Pacemakers and ICDs - NCLEX', true, 87, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Patient ID and symptom reporting. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Patient ID and symptom reporting. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Device identification is unnecessary in emergencies in this note."}, {"id": "b", "text": "Pacemaker ID card is recommended."}, {"id": "c", "text": "Dizziness/syncope should be reported."}, {"id": "d", "text": "Hiccups can signal diaphragm stimulation/lead displacement."}, {"id": "e", "text": "Hiccups are always benign in this context in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Patients should carry pacemaker ID card and report hiccups, dizziness, or syncope.', 'Pacemakers and ICDs - NCLEX', true, 88, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support ICD function? (Select all that apply)', 'During reassessment, which observations support ICD function? (Select all that apply)', '[{"id": "a", "text": "ICD shocks V-fib/V-tach per note."}, {"id": "b", "text": "ICD monitors rhythm continuously."}, {"id": "c", "text": "ICD is for sinus bradycardia only in this note."}, {"id": "d", "text": "ICD does not treat ventricular arrhythmias in this note."}, {"id": "e", "text": "ICD is indicated for sudden death risk patients."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: ICD continuously monitors rhythm and delivers shock for ventricular fibrillation or ventricular tachycardia.', 'Pacemakers and ICDs - NCLEX', true, 89, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with If ICD fires in this note? (Select all that apply)', 'Which clues are consistent with If ICD fires in this note? (Select all that apply)', '[{"id": "a", "text": "ICD firing never requires follow-up in this note."}, {"id": "b", "text": "Lie down after ICD discharge is recommended."}, {"id": "c", "text": "Exercise immediately after shock is advised in this note."}, {"id": "d", "text": "Persistent symptoms require provider notification."}, {"id": "e", "text": "Documenting shock time is recommended."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: If ICD fires, patient should lie down, note time, and notify provider if symptoms continue.', 'Pacemakers and ICDs - NCLEX', true, 90, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Bystander sensation with ICD. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Bystander sensation with ICD. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "No one near patient feels anything in this note."}, {"id": "b", "text": "Bystanders may feel mild shock."}, {"id": "c", "text": "ICD discharge is fatal to bystanders in this note."}, {"id": "d", "text": "Mild shock to bystander is noted as not dangerous."}, {"id": "e", "text": "Education reduces fear around ICD events."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: People touching the patient during ICD discharge may feel mild shock that is not dangerous.', 'Pacemakers and ICDs - NCLEX', true, 91, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving ICD storm emergency, which statements are correct? (Select all that apply)', 'For management involving ICD storm emergency, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Repeated firing is emergency in this note."}, {"id": "b", "text": "ICD storm is routine expected function in this note."}, {"id": "c", "text": "Storm implies unstable arrhythmia burden."}, {"id": "d", "text": "Immediate reporting is required."}, {"id": "e", "text": "Repeated shocks can be ignored if conscious in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Repeated ICD firing should be reported immediately as an emergency (ICD storm).', 'Pacemakers and ICDs - NCLEX', true, 92, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Chest pain initial priorities. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Chest pain initial priorities. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "ECG target is within 10 minutes."}, {"id": "b", "text": "ABCs come first in chest pain approach."}, {"id": "c", "text": "Oxygen threshold is O2 sat <90% in note."}, {"id": "d", "text": "12-lead ECG can be delayed several hours in this note."}, {"id": "e", "text": "Medications are given before ABC assessment in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Chest pain protocol starts with ABC assessment, oxygen if saturation <90%, vitals, and 12-lead ECG within 10 minutes.', 'Pacemakers and ICDs - NCLEX', true, 93, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Chest pain workflow continuation? (Select all that apply)', 'During reassessment, which observations support Chest pain workflow continuation? (Select all that apply)', '[{"id": "a", "text": "Troponin/CK-MB/BMP are listed labs."}, {"id": "b", "text": "Aspirin then nitroglycerin then morphine/heparin sequence is listed."}, {"id": "c", "text": "No labs are needed for chest pain in this note."}, {"id": "d", "text": "Large-bore IV is listed."}, {"id": "e", "text": "Heparin is given before aspirin in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Protocol includes large-bore IV access, labs (troponin, CK-MB, BMP), and meds sequence: aspirin, nitroglycerin, morphine if needed, then heparin.', 'Pacemakers and ICDs - NCLEX', true, 94, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Nitroglycerin safety in this note? (Select all that apply)', 'Which clues are consistent with Nitroglycerin safety in this note? (Select all that apply)', '[{"id": "a", "text": "BP check before NTG is emphasized."}, {"id": "b", "text": "Recent sildenafil is contraindication in this note."}, {"id": "c", "text": "SBP <90 is NTG hold criterion."}, {"id": "d", "text": "NTG is safe regardless of BP in this note."}, {"id": "e", "text": "Sildenafil timing has no relevance in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Check blood pressure before nitroglycerin; avoid nitroglycerin if systolic BP <90 or recent sildenafil use within 24–48 hours.', 'Pacemakers and ICDs - NCLEX', true, 95, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Positioning HF/SOB. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Positioning HF/SOB. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Flat Trendelenburg is best for HF/SOB in this note."}, {"id": "b", "text": "Fowler position 30–45° is listed for HF/SOB."}, {"id": "c", "text": "Breathing relief is rationale for elevated HOB."}, {"id": "d", "text": "Position has no respiratory impact in this note."}, {"id": "e", "text": "Positioning reduces preload in this note."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: For heart failure/SOB, best position is HOB elevated 30–45° (Fowler) to reduce preload and ease breathing.', 'Pacemakers and ICDs - NCLEX', true, 96, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For management involving Positioning hypotension/shock, which statements are correct? (Select all that apply)', 'For management involving Positioning hypotension/shock, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Leg lowering improves hypotension in this note."}, {"id": "b", "text": "Rationale is increased venous return."}, {"id": "c", "text": "Positioning is an early supportive intervention."}, {"id": "d", "text": "Supine with legs elevated is listed for hypotension/shock."}, {"id": "e", "text": "Sit upright is best for hypotensive shock in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: For hypotension/shock, position supine with legs elevated 15–30° to increase venous return.', 'Pacemakers and ICDs - NCLEX', true, 97, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Cardiogenic shock position caution. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Cardiogenic shock position caution. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Supine positioning is listed with caution."}, {"id": "b", "text": "Trendelenburg is avoided in cardiogenic shock."}, {"id": "c", "text": "Cardiogenic shock requires sitting upright always in this note."}, {"id": "d", "text": "Positioning differs from routine assumptions."}, {"id": "e", "text": "Trendelenburg is first-line for cardiogenic shock in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: For cardiogenic shock, note recommends supine with caution and to avoid Trendelenburg.', 'Pacemakers and ICDs - NCLEX', true, 98, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Pericarditis and post-op positioning? (Select all that apply)', 'During reassessment, which observations support Pericarditis and post-op positioning? (Select all that apply)', '[{"id": "a", "text": "Post-cardiac surgery semi-Fowler is listed."}, {"id": "b", "text": "Pericarditis is best managed flat supine in this note."}, {"id": "c", "text": "Post-op position should always be Trendelenburg in this note."}, {"id": "d", "text": "Pericarditis relieved by sit up and leaning forward."}, {"id": "e", "text": "Lung expansion is rationale for semi-Fowler post-op."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis position is sit up/lean forward; post-cardiac surgery preferred is semi-Fowler for comfort and lung expansion.', 'Pacemakers and ICDs - NCLEX', true, 99, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Lifestyle diet teaching in this note? (Select all that apply)', 'Which clues are consistent with Lifestyle diet teaching in this note? (Select all that apply)', '[{"id": "a", "text": "High-sodium canned foods are recommended in this note."}, {"id": "b", "text": "Fiber should be minimized in this note."}, {"id": "c", "text": "High-fiber fruits/vegetables are recommended."}, {"id": "d", "text": "Processed foods/deli meats/canned soups are discouraged."}, {"id": "e", "text": "Sodium target <2 g/day is listed."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Diet teaching includes sodium restriction <2 g/day, low saturated fat/cholesterol, high fiber/fruits/vegetables, and avoiding processed high-salt foods.', 'Pacemakers and ICDs - NCLEX', true, 100, 1, true);
